    PageProperties notesProps;       // Properties of notes pages (size, borders, etc.)

    PageInsertionParams(sal_uInt16 a_nInsertPos, PageNameList* a_pExchangeList = nullptr, SdDrawDocument* a_pBookmarkDoc = nullptr)
